// pages/student/MyTrainings.jsx
import React, { useState } from 'react';
import { trainings } from '../../data/mockData';
import './MyTrainings.css';

const ENROLLED = [
  {
    ...trainings[0],
    progress: 62,
    completedModules: 4,
    totalModules: 6,
    lastAccessed: '2 hours ago',
    status: 'In Progress',
    nextLesson: 'MongoDB & Database Design',
    hoursSpent: 28,
  },
  {
    ...trainings[2],
    progress: 100,
    completedModules: 6,
    totalModules: 6,
    lastAccessed: '1 week ago',
    status: 'Completed',
    nextLesson: null,
    certificateId: 'LP-DES-2024-7821',
    hoursSpent: 42,
  },
  {
    ...trainings[1],
    progress: 18,
    completedModules: 1,
    totalModules: 6,
    lastAccessed: '3 days ago',
    status: 'In Progress',
    nextLesson: 'Pandas for Data Wrangling',
    hoursSpent: 9,
  },
];

const STATUS_CONFIG = {
  'In Progress': { cls: 'status-review', icon: '▶' },
  'Completed':   { cls: 'status-offer',  icon: '✓' },
  'Paused':      { cls: 'status-applied', icon: '⏸' },
};

const colorMap = {
  lavender: '#C4B5FD',
  mint:     '#86EFAC',
  peach:    '#FCA5A5',
  cyan:     '#67E8F9',
  amber:    '#FCD34D',
};

export default function MyTrainings() {
  const [activeTab, setActiveTab] = useState('All');
  const tabs = ['All', 'In Progress', 'Completed'];
  const filtered = activeTab === 'All' ? ENROLLED : ENROLLED.filter(t => t.status === activeTab);

  const totalHours = ENROLLED.reduce((s, t) => s + t.hoursSpent, 0);
  const completed  = ENROLLED.filter(t => t.status === 'Completed').length;
  const certs      = ENROLLED.filter(t => t.certificateId).length;

  return (
    <div className="mytrainings page-enter">
      {/* Header */}
      <div className="mytrainings__header">
        <div>
          <h1 className="dashboard-title" style={{ marginBottom: 4 }}>My Trainings</h1>
          <p style={{ color: 'var(--text-secondary)', fontSize: '0.88rem' }}>
            {ENROLLED.length} enrolled courses · {completed} completed
          </p>
        </div>
        <div style={{ display: 'flex', gap: 6 }}>
          {tabs.map(t => (
            <button
              key={t}
              className={`filter-chip ${activeTab === t ? 'filter-chip--active' : ''}`}
              onClick={() => setActiveTab(t)}>
              {t}
            </button>
          ))}
        </div>
      </div>

      {/* Stats row */}
      <div className="mytrainings__stats">
        {[
          { icon: '📚', label: 'Enrolled', value: ENROLLED.length, color: 'lavender' },
          { icon: '🏆', label: 'Completed', value: completed, color: 'mint' },
          { icon: '⏱️', label: 'Hours Spent', value: totalHours, color: 'cyan' },
          { icon: '🎓', label: 'Certificates', value: certs, color: 'amber' },
        ].map(s => (
          <div key={s.label} className={`mytrainings__stat mytrainings__stat--${s.color}`}>
            <span className="mytrainings__stat-icon">{s.icon}</span>
            <span className="mytrainings__stat-val">{s.value}</span>
            <span className="mytrainings__stat-label">{s.label}</span>
          </div>
        ))}
      </div>

      {/* Course cards */}
      <div className="mytrainings__grid">
        {filtered.map(course => {
          const cfg = STATUS_CONFIG[course.status] || STATUS_CONFIG['In Progress'];
          const barColor = colorMap[course.tagColor] || '#C4B5FD';

          return (
            <div key={course.id} className="trcourse">
              {/* Thumb */}
              <div className="trcourse__thumb" style={{ '--tc': barColor }}>
                <div className="trcourse__thumb-bg" />
                <span className="trcourse__thumb-logo">{course.providerLogo}</span>
                {course.status === 'Completed' && (
                  <div className="trcourse__completed-badge">🏆 Completed</div>
                )}
              </div>

              {/* Body */}
              <div className="trcourse__body">
                <div className="trcourse__top">
                  <div>
                    <div className="trcourse__tags">
                      {course.tags.slice(0, 2).map(t => (
                        <span key={t} className={`tag tag-${course.tagColor}`}>{t}</span>
                      ))}
                    </div>
                    <h4 className="trcourse__title">{course.title}</h4>
                    <p className="trcourse__provider">{course.provider}</p>
                  </div>
                  <span className={`status-badge ${cfg.cls}`}>{cfg.icon} {course.status}</span>
                </div>

                {/* Progress */}
                <div className="trcourse__progress-block">
                  <div className="trcourse__progress-meta">
                    <span>{course.completedModules}/{course.totalModules} modules</span>
                    <span style={{ color: barColor, fontWeight: 700 }}>{course.progress}%</span>
                  </div>
                  <div className="trcourse__track">
                    <div className="trcourse__fill" style={{ width: `${course.progress}%`, background: barColor }} />
                  </div>
                </div>

                {/* Meta row */}
                <div className="trcourse__meta-row">
                  <span className="trcourse__meta">⏱️ {course.hoursSpent}h spent</span>
                  <span className="trcourse__meta">🕐 Last: {course.lastAccessed}</span>
                  {course.certificate && <span className="trcourse__meta">🏆 Certificate</span>}
                </div>

                {/* Next lesson */}
                {course.nextLesson && (
                  <div className="trcourse__next">
                    <span className="trcourse__next-label">Up next:</span>
                    <span className="trcourse__next-val">{course.nextLesson}</span>
                  </div>
                )}

                {/* Certificate */}
                {course.certificateId && (
                  <div className="trcourse__cert">
                    <span className="trcourse__cert-icon">🎓</span>
                    <div>
                      <span className="trcourse__cert-title">Certificate Earned</span>
                      <span className="trcourse__cert-id">ID: {course.certificateId}</span>
                    </div>
                    <button className="btn btn-ghost btn-sm trcourse__cert-btn">Download</button>
                  </div>
                )}

                {/* Actions */}
                <div className="trcourse__actions">
                  {course.status !== 'Completed' ? (
                    <button className="btn btn-primary btn-sm trcourse__resume-btn">
                      ▶ Resume Course
                    </button>
                  ) : (
                    <button className="btn btn-ghost btn-sm">Review Course</button>
                  )}
                  <button className="btn btn-ghost btn-sm">View Details</button>
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}
